const colors = {
  reset: '\x1b[0m',
  bold: '\x1b[1m',
  red: '\x1b[31m',
  green: '\x1b[32m',
  yellow: '\x1b[33m',
  blue: '\x1b[34m',
  magenta: '\x1b[35m',
  cyan: '\x1b[36m',
  white: '\x1b[37m',
};

export class Logger {
  private static formatMessage(color: string, prefix: string, message: string): string {
    return `${color}${colors.bold}${prefix}${colors.reset}${color} ${message}${colors.reset}`;
  }

  static info(message: string): void {
    console.log(this.formatMessage(colors.blue, 'ℹ', message));
  }

  static success(message: string): void {
    console.log(this.formatMessage(colors.green, '✓', message));
  }

  static warn(message: string): void {
    console.log(this.formatMessage(colors.yellow, '⚠', message));
  }

  static error(message: string): void {
    console.error(this.formatMessage(colors.red, '✗', message));
  }

  static step(step: number, total: number, message: string): void {
    console.log(this.formatMessage(colors.cyan, `[${step}/${total}]`, message));
  }

  static title(message: string): void {
    console.log(`\n${colors.bold}${colors.magenta}═══════════════════════════════════════${colors.reset}`);
    console.log(`${colors.bold}${colors.magenta}  ${message}${colors.reset}`);
    console.log(`${colors.bold}${colors.magenta}═══════════════════════════════════════${colors.reset}\n`);
  }

  static plain(message: string): void {
    console.log(message);
  }

  static newLine(): void {
    console.log('');
  }
}

export class Spinner {
  private frames = ['⠋', '⠙', '⠹', '⠸', '⠼', '⠴', '⠦', '⠧', '⠇', '⠏'];
  private interval: Timer | null = null;
  private currentFrame = 0;
  private message: string;

  constructor(message: string) {
    this.message = message;
  }

  start(): void {
    this.currentFrame = 0;
    this.interval = setInterval(() => {
      process.stdout.write(`\r${colors.cyan}${this.frames[this.currentFrame]}${colors.reset} ${this.message}`);
      this.currentFrame = (this.currentFrame + 1) % this.frames.length;
    }, 80);
  }

  succeed(message?: string): void {
    this.stop();
    Logger.success(message || this.message);
  }

  fail(message?: string): void {
    this.stop();
    Logger.error(message || this.message);
  }

  stop(): void {
    if (this.interval) {
      clearInterval(this.interval);
      this.interval = null;
      process.stdout.write('\r\x1b[K'); // Clear line
    }
  }

  updateMessage(message: string): void {
    this.message = message;
  }
}

