import { readFile, writeFile } from 'fs/promises';
import { existsSync } from 'fs';
import { APP_CONFIG } from '../config/cli-config';
import { Logger } from './logger';

const GRADLE_PLUGIN_FILE = APP_CONFIG.android.gradlePluginFile;
const PROBLEMATIC_LINE = 'plugins { id("org.gradle.toolchains.foojay-resolver-convention").version("0.5.0") }';
const COMMENTED_LINE = '// plugins { id("org.gradle.toolchains.foojay-resolver-convention").version("0.5.0") }';
const BACKUP_SUFFIX = '.cli-backup';

let isFixApplied = false;
let originalContent: string | null = null;

export async function applyGradleFix(): Promise<void> {
  if (isFixApplied) {
    Logger.info('Gradle fix already applied');
    return;
  }

  if (!existsSync(GRADLE_PLUGIN_FILE)) {
    Logger.warn(`Gradle plugin file not found: ${GRADLE_PLUGIN_FILE}`);
    return;
  }

  try {
    const content = await readFile(GRADLE_PLUGIN_FILE, 'utf-8');
    originalContent = content;

    if (content.includes(COMMENTED_LINE)) {
      Logger.info('Gradle fix already present in file');
      isFixApplied = true;
      return;
    }

    if (!content.includes(PROBLEMATIC_LINE)) {
      Logger.warn('Problematic Gradle line not found, skipping fix');
      return;
    }

    // Create backup
    await writeFile(`${GRADLE_PLUGIN_FILE}${BACKUP_SUFFIX}`, content);

    // Apply fix
    const fixedContent = content.replace(PROBLEMATIC_LINE, COMMENTED_LINE);
    await writeFile(GRADLE_PLUGIN_FILE, fixedContent);

    isFixApplied = true;
    Logger.success('Gradle plugin fix applied');
  } catch (error) {
    Logger.error(`Failed to apply Gradle fix: ${error}`);
    throw error;
  }
}

export async function restoreGradleFix(): Promise<void> {
  if (!isFixApplied || !originalContent) {
    return;
  }

  try {
    await writeFile(GRADLE_PLUGIN_FILE, originalContent);
    isFixApplied = false;
    originalContent = null;
    Logger.info('Gradle plugin restored to original state');
  } catch (error) {
    Logger.error(`Failed to restore Gradle file: ${error}`);
  }
}

export async function ensureGradleFixApplied(): Promise<void> {
  await applyGradleFix();
}

process.on('exit', () => {
  // Note: async operations won't work in exit handler
  // Users should manually call restoreGradleFix if needed
});

process.on('SIGINT', async () => {
  await restoreGradleFix();
  process.exit(130);
});

process.on('SIGTERM', async () => {
  await restoreGradleFix();
  process.exit(143);
});

