import { exec } from 'child_process';
import { promisify } from 'util';
import { APP_CONFIG } from '../config/cli-config';
import { Logger, Spinner } from './logger';

const execAsync = promisify(exec);

export async function listEmulators(): Promise<string[]> {
  try {
    const { stdout } = await execAsync('emulator -list-avds');
    return stdout
      .trim()
      .split('\n')
      .filter((line) => line.length > 0);
  } catch (error) {
    Logger.error('Failed to list emulators. Make sure Android SDK is installed.');
    throw error;
  }
}

export async function getRunningDevices(): Promise<string[]> {
  try {
    const { stdout } = await execAsync('adb devices');
    const lines = stdout.split('\n').slice(1); // Skip header
    return lines
      .filter((line) => line.includes('device') && !line.includes('offline'))
      .map((line) => line.split('\t')[0].trim())
      .filter((device) => device.length > 0);
  } catch (error) {
    return [];
  }
}

export async function isEmulatorRunning(): Promise<boolean> {
  const devices = await getRunningDevices();
  return devices.length > 0;
}

export async function getRunningDevice(): Promise<string | null> {
  const devices = await getRunningDevices();
  return devices.length > 0 ? devices[0] : null;
}

export async function startEmulator(
  name: string = APP_CONFIG.android.defaultEmulator
): Promise<void> {
  const spinner = new Spinner(`Starting emulator: ${name}`);

  try {
    const emulators = await listEmulators();

    if (!emulators.includes(name)) {
      throw new Error(
        `Emulator "${name}" not found. Available emulators: ${emulators.join(', ')}`
      );
    }

    // Check if already running
    if (await isEmulatorRunning()) {
      Logger.info('Emulator already running');
      return;
    }

    spinner.start();

    // Start emulator in background
    exec(`emulator -avd ${name} > /dev/null 2>&1 &`);

    // Wait for emulator to boot
    await waitForBoot(APP_CONFIG.timeouts.emulatorBoot);

    spinner.succeed(`Emulator ${name} started successfully`);
  } catch (error) {
    spinner.fail(`Failed to start emulator: ${error}`);
    throw error;
  }
}

export async function waitForBoot(timeout: number = 120000): Promise<void> {
  const startTime = Date.now();
  const spinner = new Spinner('Waiting for emulator to boot');

  try {
    spinner.start();

    while (Date.now() - startTime < timeout) {
      try {
        // Wait for device to be online
        const devices = await getRunningDevices();
        if (devices.length === 0) {
          await sleep(2000);
          continue;
        }

        // Check if boot completed
        const { stdout } = await execAsync('adb shell getprop sys.boot_completed', {
          timeout: 5000,
        });

        if (stdout.trim() === '1') {
          spinner.succeed('Emulator booted successfully');
          // Wait a bit more for stability
          await sleep(3000);
          return;
        }
      } catch (error) {
        // Device might not be ready yet, continue waiting
      }

      await sleep(2000);
    }

    throw new Error('Emulator boot timeout');
  } catch (error) {
    spinner.fail('Emulator failed to boot');
    throw error;
  }
}

export async function listIOSSimulators(): Promise<Array<{ name: string; udid: string; state: string }>> {
  try {
    const { stdout } = await execAsync('xcrun simctl list devices --json');
    const data = JSON.parse(stdout);

    const simulators: Array<{ name: string; udid: string; state: string }> = [];

    for (const runtime in data.devices) {
      const devices = data.devices[runtime];
      for (const device of devices) {
        if (device.isAvailable) {
          simulators.push({
            name: device.name,
            udid: device.udid,
            state: device.state,
          });
        }
      }
    }

    return simulators;
  } catch (error) {
    Logger.error('Failed to list iOS simulators. Make sure Xcode is installed.');
    throw error;
  }
}

export async function startIOSSimulator(deviceName: string): Promise<void> {
  const spinner = new Spinner(`Starting iOS simulator: ${deviceName}`);

  try {
    const simulators = await listIOSSimulators();
    const simulator = simulators.find((sim) => sim.name === deviceName);

    if (!simulator) {
      throw new Error(
        `Simulator "${deviceName}" not found. Available: ${simulators.map((s) => s.name).join(', ')}`
      );
    }

    if (simulator.state === 'Booted') {
      Logger.info(`Simulator "${deviceName}" already running`);
      return;
    }

    spinner.start();

    await execAsync(`xcrun simctl boot "${simulator.udid}"`);
    await execAsync('open -a Simulator');

    // Wait for simulator to be ready
    await sleep(5000);

    spinner.succeed(`iOS simulator ${deviceName} started successfully`);
  } catch (error) {
    spinner.fail(`Failed to start iOS simulator: ${error}`);
    throw error;
  }
}

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

