import { exec } from 'child_process';
import { promisify } from 'util';
import { APP_CONFIG } from '../config/cli-config';
import { Logger, Spinner } from './logger';

const execAsync = promisify(exec);

export async function isAppInstalled(packageId: string): Promise<boolean> {
  try {
    const { stdout } = await execAsync(`adb shell pm list packages ${packageId}`);
    return stdout.includes(packageId);
  } catch (error) {
    return false;
  }
}

export async function uninstallApp(packageId: string): Promise<void> {
  const spinner = new Spinner(`Uninstalling ${packageId}`);

  try {
    const installed = await isAppInstalled(packageId);

    if (!installed) {
      Logger.info('App not installed, skipping uninstall');
      return;
    }

    spinner.start();

    await execAsync(`adb uninstall ${packageId}`, {
      timeout: APP_CONFIG.timeouts.install,
    });

    spinner.succeed(`Uninstalled ${packageId}`);
  } catch (error) {
    spinner.fail(`Failed to uninstall app: ${error}`);
    throw error;
  }
}

export async function installApk(apkPath: string): Promise<void> {
  const spinner = new Spinner(`Installing APK: ${apkPath}`);

  try {
    spinner.start();

    const { stdout, stderr } = await execAsync(`adb install "${apkPath}"`, {
      timeout: APP_CONFIG.timeouts.install,
    });

    if (stderr && stderr.includes('INSTALL_FAILED')) {
      throw new Error(stderr);
    }

    if (stdout.includes('Success') || stderr.includes('Success')) {
      spinner.succeed('APK installed successfully');
    } else {
      throw new Error(stdout || stderr);
    }
  } catch (error) {
    spinner.fail(`Failed to install APK: ${error}`);
    throw error;
  }
}

export async function launchApp(packageId: string, activity: string): Promise<void> {
  try {
    await execAsync(`adb shell am start -n ${packageId}/${activity}`);
    Logger.success(`Launched ${packageId}`);
  } catch (error) {
    Logger.error(`Failed to launch app: ${error}`);
    throw error;
  }
}

export async function clearAppData(packageId: string): Promise<void> {
  try {
    await execAsync(`adb shell pm clear ${packageId}`);
    Logger.success(`Cleared app data for ${packageId}`);
  } catch (error) {
    Logger.error(`Failed to clear app data: ${error}`);
    throw error;
  }
}

export async function getAppVersion(packageId: string): Promise<string | null> {
  try {
    const { stdout } = await execAsync(`adb shell dumpsys package ${packageId} | grep versionName`);
    const match = stdout.match(/versionName=([^\s]+)/);
    return match ? match[1] : null;
  } catch (error) {
    return null;
  }
}

export async function isDeviceConnected(): Promise<boolean> {
  try {
    const { stdout } = await execAsync('adb devices');
    const lines = stdout.split('\n').slice(1);
    const devices = lines.filter((line) => line.includes('device') && !line.includes('offline'));
    return devices.length > 0;
  } catch (error) {
    return false;
  }
}

