import { Logger } from './logger';

export function detectVpnError(errorMessage: string): boolean {
  const vpnIndicators = [
    'SSL handshake exception',
    'PKIX path building failed',
    'unable to find valid certification path',
    'certificate',
    'Got SSL handshake exception',
  ];

  return vpnIndicators.some((indicator) =>
    errorMessage.toLowerCase().includes(indicator.toLowerCase())
  );
}

export function detectVersionDowngrade(errorMessage: string): boolean {
  return errorMessage.includes('INSTALL_FAILED_VERSION_DOWNGRADE');
}

export function detectGradlePluginError(errorMessage: string): boolean {
  return (
    errorMessage.includes('foojay-resolver-convention') ||
    errorMessage.includes('Plugin [id: \'org.gradle.toolchains')
  );
}

export function detectEmulatorError(errorMessage: string): boolean {
  return (
    errorMessage.includes('emulator') &&
    (errorMessage.includes('not found') || errorMessage.includes('offline'))
  );
}

export function suggestSolution(error: Error | string): string {
  const errorMessage = typeof error === 'string' ? error : error.message;

  if (detectVpnError(errorMessage)) {
    return `
╔════════════════════════════════════════════════════════════════╗
║  VPN/SSL Certificate Error Detected                            ║
╠════════════════════════════════════════════════════════════════╣
║  The build failed due to VPN interfering with SSL connections. ║
║                                                                 ║
║  Solutions:                                                     ║
║  1. Disconnect from VPN and try again                          ║
║  2. Use --offline flag if dependencies are cached              ║
║  3. Configure VPN to exclude Gradle/Maven repositories         ║
╚════════════════════════════════════════════════════════════════╝
`;
  }

  if (detectVersionDowngrade(errorMessage)) {
    return `
╔════════════════════════════════════════════════════════════════╗
║  Version Downgrade Error                                       ║
╠════════════════════════════════════════════════════════════════╣
║  A newer version of the app is already installed.              ║
║                                                                 ║
║  This CLI automatically uninstalls the old version,            ║
║  but you can also do it manually:                              ║
║  adb uninstall com.semparar.semparar.minhaconta2018            ║
╚════════════════════════════════════════════════════════════════╝
`;
  }

  if (detectGradlePluginError(errorMessage)) {
    return `
╔════════════════════════════════════════════════════════════════╗
║  Gradle Plugin Error                                           ║
╠════════════════════════════════════════════════════════════════╣
║  The Gradle plugin configuration is incompatible.              ║
║                                                                 ║
║  This CLI automatically fixes this issue, but if it persists:  ║
║  Comment out line 16 in:                                       ║
║  node_modules/@react-native/gradle-plugin/settings.gradle.kts  ║
╚════════════════════════════════════════════════════════════════╝
`;
  }

  if (detectEmulatorError(errorMessage)) {
    return `
╔════════════════════════════════════════════════════════════════╗
║  Emulator Error                                                ║
╠════════════════════════════════════════════════════════════════╣
║  The Android emulator is not running or not found.             ║
║                                                                 ║
║  Solutions:                                                     ║
║  1. Start emulator: emulator -avd <emulator-name>              ║
║  2. List emulators: emulator -list-avds                        ║
║  3. This CLI can auto-start the emulator with --run-emulator   ║
╚════════════════════════════════════════════════════════════════╝
`;
  }

  return `
╔════════════════════════════════════════════════════════════════╗
║  Build Error                                                   ║
╠════════════════════════════════════════════════════════════════╣
║  ${errorMessage.substring(0, 60).padEnd(63)}║
║                                                                 ║
║  Check the error message above for more details.               ║
╚════════════════════════════════════════════════════════════════╝
`;
}

export function handleError(error: Error | string): void {
  Logger.error('Build failed');
  Logger.newLine();

  const solution = suggestSolution(error);
  console.log(solution);

  Logger.newLine();
}

export async function withErrorHandling<T>(
  fn: () => Promise<T>,
  context: string
): Promise<T> {
  try {
    return await fn();
  } catch (error) {
    Logger.error(`${context} failed`);
    handleError(error as Error);
