import { spawn } from 'child_process';
import { promisify } from 'util';
import { exec } from 'child_process';
import { APP_CONFIG } from '../config/cli-config';
import { Logger } from '../utils/logger';
import { startEmulator, isEmulatorRunning } from '../utils/emulator';
import { handleError } from '../utils/error-handler';

const execAsync = promisify(exec);

interface DevAndroidOptions {
  emulatorName?: string;
  port?: number;
}

export async function devAndroid(options: DevAndroidOptions = {}): Promise<void> {
  const { emulatorName, port = 8081 } = options;

  Logger.title('Starting Android Development Mode');

  try {
    // Step 1: Set environment to dev
    Logger.step(1, 4, 'Setting environment to development');
    await setEnvironment();

    // Step 2: Check/Start emulator
    Logger.step(2, 4, 'Checking Android emulator');

    if (!(await isEmulatorRunning())) {
      Logger.info('Starting emulator');
      await startEmulator(emulatorName);
    } else {
      Logger.info('Emulator already running');
    }

    // Step 3: Start Metro bundler
    Logger.step(3, 4, 'Starting Metro bundler');
    const metroProcess = startMetro(port);

    // Wait a bit for Metro to start
    await sleep(3000);

    // Step 4: Run on Android
    Logger.step(4, 4, 'Running app on Android');
    await runAndroid();

    Logger.newLine();
    Logger.success('✓ App is running in development mode!');
    Logger.newLine();
    Logger.info('Press Ctrl+C to stop');
    Logger.newLine();

    // Keep process alive and show Metro logs
    await new Promise((resolve, reject) => {
      metroProcess.on('exit', (code) => {
        if (code !== 0) {
          reject(new Error(`Metro exited with code ${code}`));
        } else {
          resolve(null);
        }
      });

      process.on('SIGINT', () => {
        Logger.info('Stopping Metro bundler...');
        metroProcess.kill();
        process.exit(0);
      });
    });
  } catch (error) {
    handleError(error as Error);
    process.exit(1);
  }
}

async function setEnvironment(): Promise<void> {
  try {
    await execAsync('yarn setenv:dev', {
      cwd: APP_CONFIG.paths.root,
    });

    Logger.success('Environment set to development');
  } catch (error) {
    Logger.error('Failed to set environment');
    throw error;
  }
}

function startMetro(port: number) {
  Logger.info(`Starting Metro on port ${port}`);

  const metroProcess = spawn('yarn', ['start', '--port', port.toString()], {
    cwd: APP_CONFIG.paths.root,
    stdio: 'inherit',
    shell: true,
  });

  return metroProcess;
}

async function runAndroid(): Promise<void> {
  try {
    Logger.info('Building and installing debug APK');

    // Run react-native run-android
    const buildProcess = spawn('yarn', ['android'], {
      cwd: APP_CONFIG.paths.root,
      stdio: 'inherit',
      shell: true,
    });

    await new Promise<void>((resolve, reject) => {
      buildProcess.on('exit', (code) => {
        if (code === 0) {
          resolve();
        } else {
          reject(new Error(`Build failed with code ${code}`));
        }
      });

      buildProcess.on('error', reject);
    });

    Logger.success('App installed and launched');
  } catch (error) {
    Logger.error('Failed to run on Android');
    throw error;
  }
}

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

