import { handleError } from '../utils/error-handler';

const execAsync = promisify(exec);

interface DevIOSOptions {
  device?: string;
  port?: number;
}

export async function devIOS(options: DevIOSOptions = {}): Promise<void> {
  const { device = APP_CONFIG.ios.defaultSimulator, port = 8081 } = options;

  Logger.title('Starting iOS Development Mode');

  try {
    // Step 1: Set environment to dev
    Logger.step(1, 5, 'Setting environment to development');
    await setEnvironment();

    // Step 2: Check CocoaPods
    Logger.step(2, 5, 'Checking CocoaPods');
    await ensurePods();

    // Step 3: Start/Check iOS Simulator
