#!/usr/bin/env bun

import { Command } from 'commander';
import { buildAndroid } from './cli/commands/build-android';
import { devAndroid } from './cli/commands/dev-android';
import { devIOS } from './cli/commands/dev-ios';
import { Logger } from './cli/utils/logger';
import type { Environment } from './cli/config/cli-config';

const program = new Command();

program
  .name('semparar-cli')
  .description('SemParar Mobile Development CLI')
  .version('1.0.0');

// Build Android APK command
program
  .command('build-android')
  .description('Build Android APK')
  .option('-e, --env <environment>', 'Environment (dev, qa, prod)', 'qa')
  .option('-c, --clean', 'Clean build before building', false)
  .option('-r, --run-emulator', 'Run on emulator after build', false)
  .option('--emulator <name>', 'Emulator name to use')
  .option('--offline', 'Build in offline mode', false)
  .action(async (options) => {
    await buildAndroid({
      env: options.env as Environment,
      clean: options.clean,
      runEmulator: options.runEmulator,
      emulatorName: options.emulator,
      offline: options.offline,
    });
  });

// Android development mode command
program
  .command('dev-android')
  .description('Run Android app in development mode')
  .option('--emulator <name>', 'Emulator name to use')
  .option('-p, --port <port>', 'Metro bundler port', '8081')
  .action(async (options) => {
    await devAndroid({
      emulatorName: options.emulator,
      port: parseInt(options.port),
    });
  });

// iOS development mode command
program
  .command('dev-ios')
  .description('Run iOS app in development mode')
  .option('-d, --device <name>', 'iOS simulator name', 'iPhone 17 Pro Max')
  .option('-p, --port <port>', 'Metro bundler port', '8081')
  .action(async (options) => {
    await devIOS({
      device: options.device,
      port: parseInt(options.port),
    });
  });

// Interactive menu command
program
  .command('menu')
  .description('Show interactive menu')
  .action(async () => {
    await showInteractiveMenu();
  });

// If no command provided, show interactive menu
if (process.argv.length === 2) {
  showInteractiveMenu();
} else {
  program.parse(process.argv);
}

async function showInteractiveMenu() {
  Logger.title('SemParar Mobile CLI');

  console.log('┌─────────────────────────────────────────────┐');
  console.log('│  1. Build Android APK (QA)                  │');
  console.log('│  2. Build Android APK (QA) + Run Emulator   │');
  console.log('│  3. Build Android APK (Production)          │');
  console.log('│  4. Run Android Dev Mode                    │');
  console.log('│  5. Run iOS Dev Mode (iPhone 17 Pro Max)    │');
  console.log('│  6. Exit                                    │');
  console.log('└─────────────────────────────────────────────┘');
  Logger.newLine();

  // Use Bun's built-in prompt
  const choice = prompt('Select an option (1-6):');

  switch (choice) {
    case '1':
      await buildAndroid({ env: 'qa', runEmulator: false });
      break;
    case '2':
      await buildAndroid({ env: 'qa', runEmulator: true });
      break;
    case '3':
      await buildAndroid({ env: 'prod', runEmulator: false });
      break;
    case '4':
      await devAndroid({});
      break;
    case '5':
      await devIOS({ device: 'iPhone 17 Pro Max' });
      break;
    case '6':
      Logger.info('Goodbye!');
      process.exit(0);
      break;
    default:
      Logger.error('Invalid option');
      await showInteractiveMenu();
  }
}

