#!/usr/bin/env bun

import { buildAndroid } from './cli/commands/build-android';
import { devAndroid } from './cli/commands/dev-android';
import { devIOS } from './cli/commands/dev-ios';
import { Logger } from './cli/utils/logger';
import type { Environment } from './cli/config/cli-config';

const args = process.argv.slice(2);
const command = args[0];

// Parse arguments manually
function parseArgs() {
  const options: Record<string, any> = {};

  for (let i = 1; i < args.length; i++) {
    const arg = args[i];

    if (arg.startsWith('--')) {
      const key = arg.slice(2);
      const nextArg = args[i + 1];

      if (nextArg && !nextArg.startsWith('--') && !nextArg.startsWith('-')) {
        options[key] = nextArg;
        i++;
      } else {
        options[key] = true;
      }
    } else if (arg.startsWith('-')) {
      const key = arg.slice(1);
      const nextArg = args[i + 1];

      if (nextArg && !nextArg.startsWith('--') && !nextArg.startsWith('-')) {
        options[key] = nextArg;
        i++;
      } else {
        options[key] = true;
      }
    }
  }

  return options;
}

async function main() {
  if (!command || command === 'menu') {
    await showInteractiveMenu();
    return;
  }

  const options = parseArgs();

  switch (command) {
    case 'build-android':
      await buildAndroid({
        env: (options.env || options.e || 'qa') as Environment,
        clean: options.clean || options.c || false,
        runEmulator: options['run-emulator'] || options.r || false,
        emulatorName: options.emulator,
        offline: options.offline || false,
      });
      break;

    case 'dev-android':
      await devAndroid({
        emulatorName: options.emulator,
        port: parseInt(options.port || options.p || '8081'),
      });
      break;

    case 'dev-ios':
      await devIOS({
        device: options.device || options.d || 'iPhone 17 Pro Max',
        port: parseInt(options.port || options.p || '8081'),
      });
      break;

    case 'help':
    case '--help':
    case '-h':
      showHelp();
      break;

    default:
      Logger.error(`Unknown command: ${command}`);
      Logger.info('Run "bun cli.ts help" for usage information');
      process.exit(1);
  }
}

function showHelp() {
  console.log(`
SemParar Mobile Development CLI v1.0.0

Usage:
  bun cli.ts [command] [options]

Commands:
  build-android              Build Android APK
  dev-android                Run Android app in development mode
  dev-ios                    Run iOS app in development mode
  menu                       Show interactive menu (default)
  help                       Show this help message

Options for build-android:
  -e, --env <env>           Environment: dev, qa, prod (default: qa)
  -c, --clean               Clean build before building
  -r, --run-emulator        Run on emulator after build
  --emulator <name>         Emulator name to use
  --offline                 Build in offline mode

Options for dev-android:
  --emulator <name>         Emulator name to use
  -p, --port <port>         Metro bundler port (default: 8081)

Options for dev-ios:
  -d, --device <name>       iOS simulator name (default: iPhone 17 Pro Max)
  -p, --port <port>         Metro bundler port (default: 8081)

Examples:
  bun cli.ts build-android --env qa --run-emulator
  bun cli.ts dev-android --emulator Medium_Phone_API_36
  bun cli.ts dev-ios --device "iPhone 17 Pro Max"
  bun cli.ts menu
`);
}

main().catch((error) => {
  Logger.error(`Fatal error: ${error.message}`);
  process.exit(1);
});

