export class ProgressLogger {
  private startTime: number = 0;
  private lastOutputTime: number = 0;
  private hangThreshold: number = 30000; // 30 seconds without output = warning
  private checkInterval: Timer | null = null;
  private totalLines: number = 0;

  start(): void {
    this.startTime = Date.now();
    this.lastOutputTime = Date.now();
    this.totalLines = 0;

    Logger.info('Starting build process...');
    Logger.plain(`${colors.cyan}⏱  Elapsed: 0s${colors.reset}`);
    Logger.newLine();

    // Check for hangs every 5 seconds
    this.checkInterval = setInterval(() => {
      this.checkHang();
    }, 5000);
  }

  private checkHang(): void {
    const timeSinceLastOutput = Date.now() - this.lastOutputTime;
    const elapsed = Math.floor((Date.now() - this.startTime) / 1000);

    if (timeSinceLastOutput > this.hangThreshold) {
