export class ProgressLogger {
  private startTime: number = 0;
  private lastOutputTime: number = 0;
  private hangThreshold: number = 30000; // 30 seconds without output = warning
  private checkInterval: Timer | null = null;
  private totalLines: number = 0;

  start(): void {
    this.startTime = Date.now();
    this.lastOutputTime = Date.now();
    this.totalLines = 0;

    Logger.info('Starting build process...');
    Logger.plain(`${colors.cyan}⏱  Elapsed: 0s${colors.reset}`);
    Logger.newLine();

    // Check for hangs every 5 seconds
    this.checkInterval = setInterval(() => {
      this.checkHang();
    }, 5000);
  }

  private checkHang(): void {
    const timeSinceLastOutput = Date.now() - this.lastOutputTime;
    const elapsed = Math.floor((Date.now() - this.startTime) / 1000);

    if (timeSinceLastOutput > this.hangThreshold) {
      Logger.warn(`No output for ${Math.floor(timeSinceLastOutput / 1000)}s - build may be processing or hung (${elapsed}s elapsed)`);
    }
  }

  private getElapsedTime(): string {
    const elapsed = Math.floor((Date.now() - this.startTime) / 1000);
    const minutes = Math.floor(elapsed / 60);
    const seconds = elapsed % 60;
    return minutes > 0 ? `${minutes}m ${seconds}s` : `${seconds}s`;
  }

  processLine(line: string): void {
    this.lastOutputTime = Date.now();
    this.totalLines++;

    const trimmed = line.trim();
    if (!trimmed) return;

    // Update elapsed time indicator
    process.stdout.write(`\r${colors.cyan}⏱  Elapsed: ${this.getElapsedTime()} | Lines: ${this.totalLines}${colors.reset}`);

    // Critical errors
    if (trimmed.includes('FAILURE:') || trimmed.includes('BUILD FAILED')) {
      process.stdout.write('\n');
      Logger.error(trimmed);
      return;
    }

    // Errors
    if (
      trimmed.toLowerCase().includes('error:') ||
      trimmed.toLowerCase().includes('exception:') ||
      trimmed.includes('FAILED')
    ) {
      process.stdout.write('\n');
      console.log(`${colors.red}${trimmed}${colors.reset}`);
      return;
    }

    // Warnings
    if (
      trimmed.toLowerCase().includes('warning:') ||
      trimmed.includes('deprecated') ||
      trimmed.toLowerCase().includes('warn')
    ) {
      process.stdout.write('\n');
      console.log(`${colors.yellow}${trimmed}${colors.reset}`);
      return;
    }

    // Important progress indicators
    if (
      trimmed.startsWith('> Task :') ||
      trimmed.includes('BUILD SUCCESSFUL') ||
      trimmed.includes('actionable task') ||
      trimmed.includes('executed') ||
      trimmed.includes('Downloaded') ||
      trimmed.includes('Resolving') ||
      trimmed.includes('Downloading') ||
      trimmed.includes('Compiling') ||
      trimmed.includes('Processing')
