      process.stdout.write('\n');
      console.log(`${colors.blue}${trimmed}${colors.reset}`);
      return;
    }

    // Configuration/dependency messages
    if (
      trimmed.startsWith('> Configure project') ||
      trimmed.includes('Gradle') ||
      trimmed.includes('Android')
    ) {
      process.stdout.write('\n');
      console.log(`${colors.cyan}${trimmed}${colors.reset}`);
      return;
    }
  }

  stop(success: boolean = true): void {
    if (this.checkInterval) {
      clearInterval(this.checkInterval);
      this.checkInterval = null;
    }

    process.stdout.write('\n');
    const elapsed = this.getElapsedTime();

    if (success) {
      Logger.success(`Build completed in ${elapsed} (${this.totalLines} lines of output)`);
    } else {
      Logger.error(`Build failed after ${elapsed} (${this.totalLines} lines of output)`);
    }
  }
}

