async function buildApk(env: Environment, offline: boolean): Promise<string> {
  const variant = BUILD_VARIANTS[env];
  const capitalizedVariant = variant.charAt(0).toUpperCase() + variant.slice(1);

  Logger.info(`Building ${capitalizedVariant} APK with real-time output...`);
  Logger.newLine();

  const progressLogger = new ProgressLogger();
  progressLogger.start();

  return new Promise((resolve, reject) => {
    const offlineFlag = offline ? '--offline' : '';
    const args = ['assemble' + capitalizedVariant];
    if (offlineFlag) {
      args.push(offlineFlag);
    }

    const gradleProcess = spawn('./gradlew', args, {
      cwd: join(APP_CONFIG.paths.root, 'android'),
      shell: true,
      env: { ...process.env },
    });

    let hasError = false;
    let isKilled = false;

    // Handle Ctrl+C and process termination signals
    const cleanup = () => {
      if (!isKilled && !gradleProcess.killed) {
        isKilled = true;
        Logger.newLine();
        Logger.warn('Build interrupted by user. Stopping Gradle...');

        // Kill the entire process group to ensure all child processes are terminated
        if (gradleProcess.pid) {
          try {
            // On Unix, kill the entire process group
            process.kill(-gradleProcess.pid, 'SIGTERM');
          } catch (error) {
            // Fallback to killing just the process
            gradleProcess.kill('SIGTERM');
          }
        }

        progressLogger.stop(false);

        // Give it 2 seconds to terminate gracefully, then force kill
        setTimeout(() => {
          if (!gradleProcess.killed) {
            gradleProcess.kill('SIGKILL');
          }
        }, 2000);
      }
    };

    // Register signal handlers
    const sigintHandler = () => {
      cleanup();
      process.exit(130); // 128 + SIGINT(2)
    };

    const sigtermHandler = () => {
      cleanup();
      process.exit(143); // 128 + SIGTERM(15)
    };

    process.on('SIGINT', sigintHandler);
    process.on('SIGTERM', sigtermHandler);

    gradleProcess.stdout.on('data', (data: Buffer) => {
      const lines = data.toString().split('\n');
      lines.forEach((line) => {
        if (line.trim()) {
          progressLogger.processLine(line);
        }
      });
    });

    gradleProcess.stderr.on('data', (data: Buffer) => {
      const lines = data.toString().split('\n');
      lines.forEach((line) => {
        if (line.trim()) {
          progressLogger.processLine(line);
          if (
            line.toLowerCase().includes('error') ||
            line.toLowerCase().includes('exception') ||
            line.includes('BUILD FAILED')
          ) {
            hasError = true;
          }
        }
      });
    });

    gradleProcess.on('close', async (code) => {
      // Remove signal handlers
      process.off('SIGINT', sigintHandler);
      process.off('SIGTERM', sigtermHandler);

      progressLogger.stop(code === 0);

      if (isKilled) {
        reject(new Error('Build was interrupted by user'));
        return;
      }

      if (code === 0) {
        try {
          Logger.newLine();
          Logger.success(`${capitalizedVariant} APK built successfully`);

          // Find the APK file
          const apkPath = await findApkPath(variant);
          resolve(apkPath);
        } catch (error) {
          reject(error);
        }
      } else {
        Logger.newLine();
        Logger.error(`Gradle build failed with exit code ${code}`);
        reject(new Error(`Build process exited with code ${code}`));
      }
    });

    gradleProcess.on('error', (error) => {
      // Remove signal handlers
      process.off('SIGINT', sigintHandler);
      process.off('SIGTERM', sigtermHandler);

      progressLogger.stop(false);
      Logger.error(`Failed to start Gradle process: ${error.message}`);
      reject(error);
    });
  });
}

