import { exec, spawn } from 'child_process';
import { promisify } from 'util';
import { existsSync } from 'fs';
import { readdir } from 'fs/promises';
import { join } from 'path';
import { APP_CONFIG, BUILD_VARIANTS, type Environment } from '../config/cli-config';
import { Logger, Spinner, ProgressLogger } from '../utils/logger';
import { applyGradleFix, restoreGradleFix } from '../utils/gradle-fix';
import { handleError } from '../utils/error-handler';
import { startEmulator, isEmulatorRunning } from '../utils/emulator';
import { uninstallApp, installApk, launchApp } from '../utils/adb';

const execAsync = promisify(exec);

interface BuildOptions {
  env: Environment;
  clean?: boolean;
  runEmulator?: boolean;
  emulatorName?: string;
  offline?: boolean;
}

export async function buildAndroid(options: BuildOptions): Promise<void> {
  const { env, clean = false, runEmulator = false, emulatorName, offline = false } = options;

  Logger.title(`Building Android APK for ${env.toUpperCase()}`);

  try {
    // Step 1: Set environment
    Logger.step(1, runEmulator ? 7 : 5, `Setting environment to ${env}`);
    await setEnvironment(env);

    // Step 2: Apply Gradle fix
    Logger.step(2, runEmulator ? 7 : 5, 'Applying Gradle fix');
    await applyGradleFix();

    // Step 3: Clean build (optional)
    if (clean) {
      Logger.step(3, runEmulator ? 7 : 5, 'Cleaning build');
      await cleanBuild();
    }

    // Step 4: Build APK
    const stepNum = clean ? 4 : 3;
    Logger.step(stepNum, runEmulator ? 7 : 5, 'Building APK');
    const apkPath = await buildApk(env, offline);

    Logger.success(`APK built successfully: ${apkPath}`);
    Logger.newLine();

    // Step 5-7: Run on emulator (optional)
    if (runEmulator) {
      await installAndRunOnEmulator(apkPath, emulatorName);
    } else {
      Logger.info(`To install manually: adb install "${apkPath}"`);
    }

    Logger.newLine();
    Logger.success('✓ Build completed successfully!');
  } catch (error) {
    handleError(error as Error);
    process.exit(1);
  } finally {
    // Restore Gradle fix (optional, keeping it commented for next builds)
    // await restoreGradleFix();
  }
}

async function setEnvironment(env: Environment): Promise<void> {
  const spinner = new Spinner(`Setting environment to ${env}`);

  try {
    spinner.start();

    const scriptMap: Record<Environment, string> = {
      dev: 'setenv:dev',
      qa: 'setenv:qa',
      prod: 'setenv:prod',
    };

    await execAsync(`yarn ${scriptMap[env]}`, {
      cwd: APP_CONFIG.paths.root,
    });

    spinner.succeed(`Environment set to ${env}`);
  } catch (error) {
    spinner.fail('Failed to set environment');
    throw error;
  }
}

async function cleanBuild(): Promise<void> {
  const spinner = new Spinner('Cleaning build directory');

  try {
    spinner.start();

    // Just remove build directory, don't run gradlew clean to avoid Gradle plugin error
    await execAsync('rm -rf android/app/build', {
      cwd: APP_CONFIG.paths.root,
    });

    spinner.succeed('Build directory cleaned');
  } catch (error) {
    spinner.fail('Failed to clean build');
    throw error;
  }
}

async function buildApk(env: Environment, offline: boolean): Promise<string> {
  const variant = BUILD_VARIANTS[env];
  const capitalizedVariant = variant.charAt(0).toUpperCase() + variant.slice(1);

  Logger.info(`Building ${capitalizedVariant} APK with real-time output...`);
  Logger.newLine();

  const progressLogger = new ProgressLogger();
  progressLogger.start();

  return new Promise((resolve, reject) => {
    const offlineFlag = offline ? '--offline' : '';
    const args = ['assemble' + capitalizedVariant];
    if (offlineFlag) {
      args.push(offlineFlag);
    }

    const gradleProcess = spawn('./gradlew', args, {
      cwd: join(APP_CONFIG.paths.root, 'android'),
      shell: true,
      env: { ...process.env },
    });

    let hasError = false;

    gradleProcess.stdout.on('data', (data: Buffer) => {
      const lines = data.toString().split('\n');
      lines.forEach((line) => {
        if (line.trim()) {
          progressLogger.processLine(line);
        }
      });
    });

    gradleProcess.stderr.on('data', (data: Buffer) => {
      const lines = data.toString().split('\n');
      lines.forEach((line) => {
        if (line.trim()) {
          progressLogger.processLine(line);
          if (
            line.toLowerCase().includes('error') ||
            line.toLowerCase().includes('exception') ||
            line.includes('BUILD FAILED')
          ) {
            hasError = true;
          }
        }
      });
    });

    gradleProcess.on('close', async (code) => {
      progressLogger.stop(code === 0);

      if (code === 0) {
        try {
          Logger.newLine();
          Logger.success(`${capitalizedVariant} APK built successfully`);

          // Find the APK file
          const apkPath = await findApkPath(variant);
          resolve(apkPath);
        } catch (error) {
          reject(error);
        }
      } else {
        Logger.newLine();
        Logger.error(`Gradle build failed with exit code ${code}`);
        reject(new Error(`Build process exited with code ${code}`));
      }
    });

    gradleProcess.on('error', (error) => {
      progressLogger.stop(false);
      Logger.error(`Failed to start Gradle process: ${error.message}`);
      reject(error);
    });
  });
}

async function findApkPath(variant: string): Promise<string> {
  const buildDir = join(APP_CONFIG.paths.root, APP_CONFIG.android.buildDir, variant);

  if (!existsSync(buildDir)) {
    throw new Error(`Build directory not found: ${buildDir}`);
  }

  const files = await readdir(buildDir);
  const universalApk = files.find(
    (file) => file.includes('universal') && file.endsWith('.apk')
  );

  if (!universalApk) {
    throw new Error('Universal APK not found in build directory');
  }

  return join(buildDir, universalApk);
}

async function installAndRunOnEmulator(
  apkPath: string,
  emulatorName?: string
): Promise<void> {
  try {
    // Step 5: Check/Start emulator
    Logger.step(5, 7, 'Checking emulator');

    if (!(await isEmulatorRunning())) {
      Logger.info('Starting emulator');
      await startEmulator(emulatorName);
    } else {
      Logger.info('Emulator already running');
    }

    // Step 6: Uninstall old version and install new APK
    Logger.step(6, 7, 'Installing APK on emulator');

    await uninstallApp(APP_CONFIG.android.packageId);
    await installApk(apkPath);

    // Step 7: Launch app
    Logger.step(7, 7, 'Launching app');

    await launchApp(APP_CONFIG.android.packageId, APP_CONFIG.android.mainActivity);

    Logger.newLine();
    Logger.success('App is now running on emulator!');
  } catch (error) {
    Logger.error('Failed to install/run on emulator');
    throw error;
  }
}

