import { exec } from 'child_process';
import { promisify } from 'util';
import { Logger } from './logger';

const execAsync = promisify(exec);

export async function killGradleProcesses(): Promise<void> {
  try {
    // Kill any running Gradle daemons
    await execAsync('pkill -f "GradleDaemon"', { timeout: 5000 }).catch(() => {
      // Ignore errors if no processes found
    });

    // Kill any gradle/gradlew processes
    await execAsync('pkill -f "gradlew"', { timeout: 5000 }).catch(() => {
      // Ignore errors if no processes found
    });

    Logger.success('All Gradle processes terminated');
  } catch (error) {
    // Ignore errors - likely means no processes were running
  }
}

export async function listGradleProcesses(): Promise<string[]> {
  try {
    const { stdout } = await execAsync(
      'ps aux | grep -i gradle | grep -v grep',
      { timeout: 5000 }
    );

    const lines = stdout.trim().split('\n').filter((line) => line.trim());
    return lines;
  } catch (error) {
    return []; // No processes found
  }
}

export async function checkOrphanedProcesses(): Promise<void> {
  const processes = await listGradleProcesses();

  if (processes.length > 0) {
    Logger.warn(`Found ${processes.length} Gradle process(es) still running:`);
    processes.forEach((proc) => {
      const parts = proc.trim().split(/\s+/);
      const pid = parts[1];
      Logger.plain(`  PID ${pid}: ${parts.slice(10).join(' ')}`);
    });
    Logger.newLine();
    Logger.info('Run "bun cli.ts kill-gradle" to clean up');
  }
}

